-- W1.6 questions batch 7795/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('promotion-6e2f88c7-moex-00004', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-916530c6', 'sub-promotion-6e2f88c7-01', NULL, 'essay', '甲因配偶乙於家中自殺，欲搬家並自行將自住之透天房屋出售。甲因同
時積欠債務而欲將該房屋以較高價格出售，乃隱瞞上開兇宅之事實，連
同土地與建物以新臺幣（以下同）1,000 萬元出售給不知情的買家丙。丙
嗣後才發現原來所買為兇宅，實際行情應只有 700 萬元。丙嫌居住該屋
不吉利，也再將該屋出售，此時雖然丙誠實地於出售資訊中明示此一房
屋曾為兇宅的事實，但是仍吸引特別喜愛兇宅的房地產大亨丁，丁為能
早日取得所有權，明知為兇宅仍願意出價 1,100 萬元購買該屋，丙乃迅
速將房屋出售給丁並取得丁交付之1,100萬元對價。請問甲之刑責為何？
（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "12e62ec36437", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0507", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00005', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'essay', '乙竊占甲所有之A地，而將之出租予丙，丙乃不知乙非 A地所有權人之
事實。乙與丙約定租金每年新臺幣 200萬元。丙在 A地上種植蘋果樹，
三年後結實纍纍。於蘋果即將收成之際，甲竟出現在丙之面前，並向丙
主張 A地上收成之蘋果皆屬甲之所有。丙十分錯愕！
試問，甲與乙間；甲與丙間；乙與丙間之法律關係各如何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00006', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'essay', '乙向甲承租甲所有之 A地，租金每月新臺幣（下同）10 萬元。乙在徵得
甲之同意下，乃以其自己之名義召請丙，擬在 A地上搭建一間溫室，以
便栽種溫室栽培作物。
稍後，因 A地地質之因素，丙雖耗盡一切努力，該溫室終究無法搭建完
成。惟丙仍向乙請求 100 萬元之工程款。蓋丙表示，於施工前丙業已告
知乙A地地質之相關缺陷。乙則轉而向甲請求償還該100萬元之工程款。
試問，乙與丙間；甲與乙間之法律關係各如何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00007', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '甲女於滿16歲生日，收到20歲大學生乙男贈送之H手機。3日後，甲將未拆封之H，以新臺幣 4萬元出售並交付於23歲丙。下列關於贈與契約與所有權之敘述，何者正確？', '["甲、乙間H手機贈與契約，不生效力", "甲未曾取得H手機之所有權", "丙尚未取得H手機之所有權", "甲、丙間H手機買賣契約，有效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00008', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '甲乙於民國100年3月5日訂立買賣契約，甲將其所有之名貴珠寶以新臺幣1,000萬元出賣予乙， 當天銀貨兩訖。2個月後，甲主張係受乙之脅迫而為前述之行為，並於同年5月8日撤銷所有意思 表示。甲若欲依民法第767條規定之物上請求權向乙請求返還該名貴珠寶，消滅時效應於何日完成？', '["民國115年3月5日", "民國115年3月6日", "民國115年5月8日", "民國115年5月9日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00009', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '下列關於民法真正條件規定之敘述，何者正確？', '["公司經理人之報酬請求權，以通過董事會普通決議為停止條件", "以客觀上不能實現之事實為內容之條件，為民法之不能條件", "法律行為成立時，其成就與否業已確定，為民法之既成條件", "依當事人之特約，使條件成就之效果，不於條件成就之時發生者，依其特約 13540 13740"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00010', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '下列關於意思表示之敘述，何者錯誤？', '["單獨虛偽意思表示之規定，僅於法律行為始有適用之必要", "當事人不能主張隱藏行為以對抗善意第三人", "動機錯誤，得主張撤銷", "傳達錯誤者原則上傳達人或傳達機關所誤傳之意思表示對表意人仍為有效，但表意人得依照意 思表示錯誤之規定而撤銷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00011', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '久病之甲，於16歲時為自書遺囑，載明將其所有之金錶遺贈予乙。半年後，又與成年之丙訂立死 因贈與契約。甲死亡時，關於金錶之權利，下列敘述何者正確？', '["乙取得金錶之受贈權", "丙取得金錶之受贈權", "乙、丙共有金錶之受贈權", "未成年之甲所立遺囑及死因贈與契約皆無效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00012', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '甲公司參與乙公司（以下簡稱甲、乙）之設備校驗工作，甲乙雙方對於校驗工作應計價收費一事， 有達成共識，但對於收費標準，均無法達成協議。嗣後，乙一直要求甲支援，甲迫於無奈，繼續 依約校驗，但一直要求乙要協商收費標準，乙均虛與委蛇。數年後，乙主張甲長期都無償支援設 備校驗工作，兩造間係無償契約，其不用付工程費用。下列敘述何者正確？', '["甲長期無償支援設備校驗工作，本件確屬無償契約無誤", "甲乙雙方就校驗工作應計價收費，均有共識。甲長期要求乙協商收費標準，乙虛與委蛇，嗣後 卻主張不用付工程費用，依實務見解，其權利行使，違反誠信原則", "既然雙方並未訂立書面契約，而約定其收費標準，即不發生有償之效力", "甲長期參與設備校驗工作，故甲得依民法上誠信原則為請求權基礎，向乙主張工程費用之給付"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00013', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '甲於炎炎夏日向大賣場乙購買冷暖氣機一台，乙保證該機型之冷暖氣功能皆符合政府節能標章之 要求並可以維持室內溫度 25 度恆溫，甲遂同意購買並約定由乙送貨至甲指定場所安裝。安裝好 後，甲隨即付清尾款。7 個月後，天氣轉冷，甲欲使用暖氣功能時，始發現該機在暖氣模式下仍 是冷風而無法吹出暖風。關於買賣瑕疵擔保責任，下列敘述何者正確？', '["冷暖氣機之買賣，屬於物之買賣，但乙除物之瑕疵擔保責任外，仍應負權利無缺擔保責任", "甲於物交付時起經過6個月後始發現瑕疵，依民法第365條有關買受人權利行使期間之規定， 不得再主張買賣瑕疵擔保責任", "冷暖氣機無法吹出暖風，甲僅得主張減少價金，不得主張解除契約", "甲發現該機無法吹出暖風時，應先定相當期限，請求乙修補之。乙如不於所定期限內修補瑕疵 時，甲始得請求解除契約"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:55+00:00", "source_pdf_sha1": "2464fc85e661", "answer_pdf_sha1": "2b998633fade", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL)
